use std::collections::HashMap;
use dashmap::DashMap;

#[derive(Debug)]
pub struct ConfigStore {
    data: DashMap<String, String>,
}

impl ConfigStore {
    pub fn new() -> Self {
        ConfigStore { data: DashMap::new() }
    }

    pub fn set_config(&self, key: &str, value: &str) {
        self.data.insert(key.to_string(), value.to_string());
    }

    pub fn get_config(&self, key: &str) -> Option<String> {
        self.data.get(key).map(|entry| entry.value().clone())
    }

    pub fn contains_key(&self, key: &str) -> bool {
        self.data.contains_key(key)
    }
}

fn main() {
    let store = ConfigStore::new();
    store.set_config("theme_color", "dark_blue");
    store.set_config("widget_layout", "grid-3-col");

    if let Some(color) = store.get_config("theme_color") {
        println!("Retrieved theme color: {}", color);
    }

    let exists = store.contains_key("non_existent_setting");
    println!("Does 'non_existent_setting' exist? {}", if !exists { "No" } else { "Yes" });
}

use dashmap::DashMap;
use std::sync::Arc;

struct SessionStore {
    tokens: Arc<DashMap<String, i64>>
}

impl SessionStore {
    fn new() -> Self {
        SessionStore {
            tokens: Arc::new(DashMap::new())
        }
    }

    fn record_token(&self, user_id: &str, expiry_timestamp: i64) {
        let key = format!("user_{}", user_id);
        self.tokens.insert(key, expiry_timestamp);
        println!("Recorded token for {} -> {}", user_id, expiry_timestamp);
    }

    fn check_token(&self, user_id: &str) -> Option<i64> {
        let key = format!("user_{}", user_id);
        self.tokens.get(&key).map(|entry| *entry.value())
    }

    fn cleanup_expired(&self, current_time: i64) {
        let mut expired_keys = Vec::new();
        for entry in self.tokens.iter() {
            if let Some(expiry) = entry.value().checked_sub(100).and_then(|v| if v < current_time { Some(v) } else { None }) {
                expired_keys.push(entry.key().clone());
            }
        }

        for key in expired_keys {
            self.tokens.remove(&key);
        }
    }
}

fn main() {
    let store = SessionStore::new();
    store.record_token("alice", 1678886400);
    store.record_token("bob", 1678995200);

    println!("Checking token for alice: {}", store.check_token("alice").unwrap_or(-1));

    let current_time = 1678886450;
    store.cleanup_expired(current_time);
    println!("Cleanup finished.");
}

use dashmap::DashMap;
use std::thread;
use std::time::Duration;

fn main() {
    let shared_map: DashMap<String, i32> = DashMap::new();
    shared_map.insert("key1".to_string(), 1);
    shared_map.insert("key2".to_string(), 2);

    let mut handles = vec![];

    for i in 0..5 {
        let map_clone = shared_map.clone();
        let handle = thread::spawn(move || {
            thread::sleep(Duration::from_millis(10 * i as u64));
            if let Some(entry) = map_clone.get("key1") {
                println!("Thread {}: Found key1 with value {}", i, entry.value());
            }
            map_clone.insert(format!("thread_{}", i), i);
        });
        handles.push(handle);
    }

    for handle in handles {
        handle.join().unwrap();
    }
}

use dashmap::DashMap;
use std::sync::Arc;
use std::thread;
use std::time::Duration;

type TelemetryStore = Arc<DashMap<String, Vec<i32>>>;

fn main() {
    let store: TelemetryStore = Arc::new(DashMap::new());

    let mut handles = vec![];

    for i in 1..=5 {
        let store_clone = Arc::clone(&store);
        let handle = thread::spawn(move || {
            let device_id = format!("sensor_{}", i % 3 + 1);
            let reading: i32 = (i * 10) as i32;

            println!("Thread {} writing to {}: {}", i, device_id, reading);

            store_clone.entry(device_id.clone()).or_insert(vec![reading]).value_mut().push(reading);
        });
        handles.push(handle);
    }

    for handle in handles {
        handle.join().unwrap();
    }

    println!("n--- Final State ---");
    for entry in store.iter() {
        println!("Device {}: Readings {:?}", entry.key(), entry.value());
    }
}

use dashmap::DashMap;
use std::sync::Arc;

#[derive(Debug)]
pub struct PasswordEntry {
    pub service: String,
    pub encrypted_vault: Vec<u8>,
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let shared_passwords: Arc<DashMap<String, PasswordEntry>> = Arc::new(DashMap::new());

    shared_passwords.insert("google".to_string(), PasswordEntry {
        service: "Google".to_string(),
        encrypted_vault: b"abcde".to_vec(),
    });

    let reader_arc = Arc::clone(&shared_passwords);
    std::thread::spawn(move || {
        for entry in reader_arc.iter() {
            println!("Reader thread sees service: {}", entry.key());
        }
    });

    let writer_arc = Arc::clone(&shared_passwords);
    std::thread::sleep(std::time::Duration::from_millis(50));
    writer_arc.insert("github".to_string(), PasswordEntry {
        service: "GitHub".to_string(),
        encrypted_vault: b"ghijkl".to_vec(),
    });

    std::thread::sleep(std::time::Duration::from_millis(100));

    println!("Final check of all entries:");
    for entry in shared_passwords.iter() {
        println!("Service: {}, Vault Size: {}", entry.key(), entry.value().encrypted_vault.len());
    }

    Ok(())
}
